/// Resolve the cocycle congruence algebraically.
///
/// Builds AᵀA and Aᵀr incrementally triple by triple — the same iteration
/// structure as coherence_functional(). Each triple contributes a small-rank
/// update to the accumulating d×d system. The final inversion is ONE d×d
/// solve, but the ACCUMULATION is triple-local.
///
/// For small n (3-5): d×d is 3-10, fast directly.
/// For large n: the d×d matrix is SPARSE because each triple only touches
/// directions involving its 3 nodes. The accumulation exploits this sparsity
/// even though the final solve is dense.
pub fn resolve(delta: &Delta) -> CongruenceResolution {
    let dirs = matrix::independent_dims(delta.dim);
    let d = dirs.len();

    // The coordinator resolves whatever it receives. No gates.
    // The metabolic horizon (d_max) is enforced UPSTREAM by the caller
    // that constructs the Delta — perception and escalation select
    // the spectral dimension m such that d fits within the horizon.
    // The coordinator trusts the Delta it was given.

    // Accumulate AᵀA and Aᵀr using the single triple iterator
    let mut ata = vec![vec![Q::zero(); d]; d];
    let mut atr = vec![Q::zero(); d];
    let mut total_coherence = Q::zero();

    // L1 subgradient: sign(r) × perturbation instead of r × perturbation.
    // The topology is holonomic — proportional, not squared.
    // AᵀA structure preserved (positive semidefinite from |p|²).
    // The right-hand side uses sign(r) to follow L1 geometry.
    for_each_residual(delta, |i, j, k, l, r_val| {
        // L1 coherence: Σ|R|, not Σ R²
        if r_val < &Q::zero() { total_coherence -= r_val; } else { total_coherence += r_val; }

        // Sign of residual for L1 subgradient
        let sign_r = if r_val < &Q::zero() {
            Q::new(BigInt::from(-1), BigInt::from(1))
        } else {
            Q::new(BigInt::from(1), BigInt::from(1))
        };

        // Sparse perturbation row — only compute nonzero entries
        let mut pert_row: Vec<(usize, Q)> = Vec::new();
        for (idx, &(dir_r, dir_s)) in dirs.iter().enumerate() {
            let p = residual_perturbation(delta, i, j, k, l, dir_r, dir_s);
            if !p.is_zero() {
                pert_row.push((idx, p));
            }
        }

        // L1 subgradient: Aᵀ·sign(r) instead of Aᵀ·r
        for &(ci, ref pi) in &pert_row {
            atr[ci] = &atr[ci] + &(pi * &sign_r);
            for &(cj, ref pj) in &pert_row {
                ata[ci][cj] = &ata[ci][cj] + &(pi * pj);
            }
        }
    });

    if total_coherence.is_zero() {
        return CongruenceResolution {
            directions: dirs,
            epsilon: vec![Q::zero(); d],
            resolved: true,
            coherence_before: Q::zero(),
            predicted_coherence_after: Q::zero(),
            cohomology_dim: 0,
            kernel: vec![],
        };
    }

    // D.COHOMOLOGY.1: measure the dimension of H^1
    // rank(AᵀA) = number of resolvable directions (coboundaries)
    // d - rank = number of independent obstructions (cohomology classes)
    let ata_rank = matrix::rank(&ata);
    let cohomology_dim = d.saturating_sub(ata_rank);

    // Compute the kernel of AᵀA — the space of cohomological freedom.
    // kernel(AᵀA) = {v : AᵀA·v = 0} — directions where the perturbation
    // Jacobian has no first-order effect on coherence.
    // This IS the space of agency: when non-empty, multiple valid
    // perturbation directions exist and the choice between them
    // is not determined by the cocycle equation.
    let kernel = if cohomology_dim > 0 {
        matrix::nullspace(&ata)
    } else {
        vec![]
    };

    // Solve AᵀA·ε = -Aᵀr — one d×d inversion
    let mut epsilon = match matrix::invert(&ata) {
        Some(ata_inv) => {
            let mut eps = vec![Q::zero(); d];
            for i in 0..d {
                for j in 0..d {
                    eps[i] = &eps[i] - &(&ata_inv[i][j] * &atr[j]);
                }
            }
            eps
        }
        None => {
            // Singular — find the direction with largest |Aᵀr| component
            let best = atr.iter().enumerate()
                .max_by(|(_, a), (_, b)| {
                    let aa = if *a < &Q::zero() { -(*a).clone() } else { (*a).clone() };
                    let bb = if *b < &Q::zero() { -(*b).clone() } else { (*b).clone() };
                    aa.cmp(&bb)
                })
                .map(|(i, _)| i)
                .unwrap_or(0);
            let mut eps = vec![Q::zero(); d];
            let step = Q::new(BigInt::from(1), BigInt::from(20));
            eps[best] = if atr[best] > Q::zero() { -step } else { step };
            eps
        }
    };

    // Cap step size: max component ≤ 1/20
    let max_abs = epsilon.iter()
        .map(|e| if e < &Q::zero() { -e.clone() } else { e.clone() })
        .max()
        .unwrap_or(Q::one());
    let cap = Q::new(BigInt::from(1), BigInt::from(20));
    if max_abs > cap {
        let scale = &cap / &max_abs;
        epsilon = epsilon.iter().map(|e| e * &scale).collect();
    }

    // Predict coherence using the single triple iterator
    let mut predicted_c = Q::zero();
    let eps_ref = &epsilon; // borrow for closure
    for_each_residual(delta, |i, j, k, l, r_val| {
        let mut new_r = r_val.clone();
        for (idx, &(dir_r, dir_s)) in dirs.iter().enumerate() {
            if eps_ref[idx].is_zero() { continue; }
            let pert = residual_perturbation(delta, i, j, k, l, dir_r, dir_s);
            if !pert.is_zero() {
                new_r = &new_r + &(&pert * &eps_ref[idx]);
            }
        }
        if new_r < Q::zero() { predicted_c -= &new_r; } else { predicted_c += &new_r; }
    });

    CongruenceResolution {
        directions: dirs,
        epsilon,
        resolved: true,
        coherence_before: total_coherence,
        predicted_coherence_after: predicted_c,
        cohomology_dim,
        kernel,
    }
}

/// Iterated algebraic resolution.
///
/// Each iteration: decompose → resolve → apply → decompose new residual.
/// The residual shrinks quadratically: each step eliminates the linear
/// component, leaving only quadratic cross-terms from the group product.
/// The next iteration eliminates those. Convergence: residual squares each step.
///
/// This is the algebraic chain rule — not differential calculus.
/// The cocycle equation defines the residual. The perturbation matrix
/// defines the resolution. The group product defines the composition.
/// The iteration defines the convergence.
///
/// Returns the composed operator (product of all iteration operators)
/// and the final resolution state.
pub fn iterated_resolve(
    delta: &Delta,
    max_iterations: usize,
) -> Option<(Operator, CongruenceResolution)> {
    let n = delta.dim;
    let dirs = matrix::independent_dims(n);

    // Start with identity operator — will accumulate compositions
    let mut composed_mat = matrix::identity(n);
    let mut composed_inv = matrix::identity(n);
    let mut current_delta = delta.clone();
    let mut last_resolution = resolve(&current_delta);

    if last_resolution.coherence_before.is_zero() {
        return None; // Already coherent
    }

    for _iter in 0..max_iterations {
        let res = resolve(&current_delta);

        if res.coherence_before.is_zero() {
            break; // Converged
        }

        // Build operator from this iteration's epsilon
        let iter_op = match matrix::operator_from_epsilons(&res.epsilon, &dirs, n, 0) {
            Some(op) => op,
            None => break,
        };

        // Apply to current delta
        let perturbed = match iter_op.apply(&current_delta) {
            Ok(p) => p,
            Err(_) => break,
        };
        current_delta = crate::engine::pi_g_project(&perturbed);

        // Compose: A_total = A_iter · A_previous
        // This is the algebraic chain rule — group product, not sum
        composed_mat = matrix::mul(&iter_op.matrix, &composed_mat);
        composed_inv = matrix::mul(&composed_inv, &iter_op.matrix_inv);

        last_resolution = res;

        // Check convergence: if coherence is very small, stop
        let new_c = crate::engine::coherence_functional(&current_delta);
        if new_c < Q::new(BigInt::from(1), BigInt::from(1000000)) {
            last_resolution.predicted_coherence_after = new_c;
            break;
        }
    }

    let det_val = matrix::det(&composed_mat);
    if det_val <= Q::zero() { return None; }

    let composed_op = Operator {
        id: 0,
        matrix: composed_mat,
        matrix_inv: composed_inv,
        det_sign_positive: true,
    };

    Some((composed_op, last_resolution))
}

/// Single-function entry point: iterated algebraic resolution.
/// Resolves the cocycle congruence through algebraic iteration.
/// Each step is exact. Convergence is quadratic (residual squares each step).
/// Returns None if the state is already coherent.
pub fn propose(delta: &Delta) -> Option<(Operator, CongruenceResolution)> {
    // Scale iterations inversely with dimension — higher dims have larger
    // rational denominators that grow through iteration. For 3×3: 3 iterations.
    // For 4×4+: single resolution (the linear step is already good).
    let iters = if delta.dim <= 3 { 3 } else { 1 };
    iterated_resolve(delta, iters)
}

/// Evaluate a single coordinate in the operator space.
/// Used by the COORDINATE_SWEEP socket command for distributed evaluation.
pub fn evaluate_coordinate_nd(
    delta: &Delta,
    epsilon: &[Q],
    c_before: &Q,
) -> Option<(Q, Q)> {
    let dirs = matrix::independent_dims(delta.dim);
    if epsilon.len() != dirs.len() { return None; }
    let op = matrix::operator_from_epsilons(epsilon, &dirs, delta.dim, 0)?;
    let perturbed = op.apply(delta).ok()?;
    let projected = pi_g_project(&perturbed);
    let c_after = coherence_functional(&projected);
    let c_delta = &c_after - c_before;
    Some((c_after, c_delta))
}

// ─── D.COORD.BASIS.1 — Coordinator as Basis Generator ────────────────

/// The optimal direction ε* in operator space. This is the coordinator's
/// primary output — not an operator, but the BASIS against which all
/// operators are measured.
///
/// α = ⟨vec(A-I), ε*⟩ / ‖ε*‖² — the alignment score.
/// ω from sluice weight — the temporal trust score.
/// (α, ω) together form the complete measurement coordinate.
#[derive(Debug, Clone)]
pub struct OptimalBasis {
    /// The optimal direction ε* ∈ Q^d where d = n(n-1)/2.
    pub direction: Vec<Q>,
    /// The independent operator directions.
    pub dims: Vec<(usize, usize)>,
    /// ‖ε*‖² — precomputed for alignment score denominator.
    pub norm_squared: Q,
    /// C(Δ) at the state where this basis was computed.
    pub coherence: Q,
    /// K-index when computed — for staleness detection.
    pub computed_at_k: u64,
}

impl OptimalBasis {
    /// Compute the optimal basis from a Delta state.
    /// This IS the coordinator's resolve() output, repackaged as a basis.
    pub fn from_delta(delta: &Delta, k_index: u64) -> Self {
        let resolution = resolve(delta);
        let norm: Q = resolution.epsilon.iter()
            .map(|e| if e < &Q::zero() { -e.clone() } else { e.clone() })
            .sum();
        Self {
            direction: resolution.epsilon,
            dims: resolution.directions,
            norm_squared: norm, // L1 norm (name kept for backward compat)
            coherence: resolution.coherence_before,
            computed_at_k: k_index,
        }
    }

    /// D.COORD.ALIGN.1 — Alignment score of any operator against ε*.
    ///
    /// α = ⟨vec(A-I), ε*⟩_Q / ‖ε*‖²_Q
    ///
    /// α = 1:  operator IS the optimal direction exactly
    /// α = 0:  operator is orthogonal (no coherence improvement in this direction)
    /// α < 0:  operator opposes optimal (increases coherence)
    ///
    /// One inner product. O(d) BigRational operations. Exact.
    pub fn alignment_score(&self, operator: &Operator) -> Q {
        if self.norm_squared.is_zero() {
            return Q::zero(); // Basis is zero — state is already coherent
        }

        let n = operator.matrix.len();
        let mut inner_product = Q::zero();

        // Vectorize A - I: extract the antisymmetric perturbation components
        for (idx, &(r, s)) in self.dims.iter().enumerate() {
            if r >= n || s >= n { continue; }
            // The antisymmetric component: (A[r][s] - A[s][r]) / 2
            // For our operators: A[r][s] = ε, A[s][r] = -ε, so component = ε
            let component = &operator.matrix[r][s];
            inner_product = &inner_product + &(component * &self.direction[idx]);
        }

        &inner_product / &self.norm_squared
    }

    /// Is this basis stale? Returns true if it should be recomputed.
    pub fn is_stale(&self, current_k: u64, refresh_interval: u64) -> bool {
        current_k.saturating_sub(self.computed_at_k) >= refresh_interval
    }

    /// D.COORD.GENESIS.1 — Genesis alignment score.
    ///
    /// α_genesis = ⟨vec(A-I), direction_toward_genesis⟩ / ‖direction_toward_genesis‖²
    ///
    /// The direction_toward_genesis is the difference between genesis Delta
    /// and current Delta, projected onto the independent operator dimensions.
    /// High α_genesis = this operator moves toward the axiom foundation.
    /// Low α_genesis = this operator moves away from the axiom foundation.
    ///
    /// (α_local, α_genesis) together: locally coherent AND axiom-grounded,
    /// or locally coherent but drifting from the foundation.
    pub fn genesis_alignment(&self, operator: &Operator, current: &Delta, genesis: &Delta) -> Q {
        let n = current.dim;
        let m = current.m;

        // Compute direction toward genesis: for each independent dim (r,s),
        // the component is the projection of (genesis - current) onto that direction
        let mut genesis_dir = vec![Q::zero(); self.dims.len()];
        let mut genesis_norm_sq = Q::zero();

        for (idx, &(r, s)) in self.dims.iter().enumerate() {
            // Sum across coordinate dimensions m
            let mut component = Q::zero();
            for l in 0..m {
                let diff = &genesis.entries[r][s][l] - &current.entries[r][s][l];
                component = &component + &diff;
            }
            genesis_dir[idx] = component.clone();
            genesis_norm_sq = &genesis_norm_sq + &(&component * &component);
        }

        if genesis_norm_sq.is_zero() {
            return Q::one(); // Already at genesis — perfect alignment by definition
        }

        // Inner product of operator direction with genesis direction
        let mut inner = Q::zero();
        for (idx, &(r, s)) in self.dims.iter().enumerate() {
            if r >= n || s >= n { continue; }
            let component = &operator.matrix[r][s];
            inner = &inner + &(component * &genesis_dir[idx]);
        }

        &inner / &genesis_norm_sq
    }
}

// ─── T.TRANSMUTE.1 — m-Expansion Trigger ─────────────────────────────
//
// The m-expansion trigger fires when transformation is exhausted
// within the current coordinate dimension m.
//
// Condition: after resolve(), if
//   (1) C_after > 0              — residual remains
//   (2) AᵀA is invertible        — n is sufficient (spatial directions available)
//   (3) epsilon is non-zero       — the system attempted resolution
//   (4) C_after / C_before > 9/10 — resolution barely reduced coherence
//   (5) The per-triple residual vectors r_{ijk} ∈ Q^m have rank = m
//       (residuals span all m coordinate dimensions — saturated)
//
// Then: the current m coordinates are fully occupied by the residual
// AND the operator could not reduce it. The relational structure
// requires more coordinate dimensions than m provides.
//
// The new coordinate's initial values derive from the post-resolution
// residual pattern — the component the m-dimensional resolution
// could not capture. Not zero. The residual IS the new axis direction.
//
// Derives from: A.1 (rational state — entries in Q^m),
//               A.4 (group closure — operators in GL_n(Q)),
//               T.3 (cocycle condition — C(Δ) measures path consistency)
//
// Register: T.TRANSMUTE.1 — NOMINATED → LOCKED when implementation verified.

/// Detect coordinate-dimension saturation.
///
/// Returns Some(new_m) when the residual spans all m coordinates
/// and resolve() cannot reduce coherence — signaling that the
/// relational structure requires m+1 coordinate dimensions.
pub fn detect_m_expansion_need(delta: &Delta) -> Option<usize> {
    let resolution = resolve(delta);
    let m = delta.m;

    // Condition 1: residual remains
    if resolution.coherence_before.is_zero() { return None; }

    // Condition 2+3: AᵀA was invertible and produced non-zero epsilon
    let eps_norm: Q = resolution.epsilon.iter()
        .map(|e| if e < &Q::zero() { -e.clone() } else { e.clone() })
        .sum();
    if eps_norm.is_zero() { return None; } // n-expansion territory, not m

    // Condition 4: resolution barely helped (< 10% reduction)
    if resolution.predicted_coherence_after.is_zero() { return None; }
    let ratio = &resolution.predicted_coherence_after / &resolution.coherence_before;
    let threshold = Q::new(BigInt::from(9), BigInt::from(10));
    if ratio <= threshold { return None; } // resolution is working, m is sufficient

    // Condition 5: residual spans all m coordinates
    // Collect per-coordinate coherence: C_l = Σ |R_{ijk,l}|
    let mut c_per_coord = vec![Q::zero(); m];
    for_each_residual(delta, |_i, _j, _k, l, r| {
        if r < &Q::zero() { c_per_coord[l] -= r; } else { c_per_coord[l] += r; }
    });
    // All m coordinates must carry non-zero residual (saturated)
    let all_coords_active = c_per_coord.iter().all(|c| !c.is_zero());
    if !all_coords_active { return None; } // some coords are resolved, m is not saturated

    // All conditions met: m is insufficient
    Some(m + 1)
}

/// Expand coordinate dimension of a Delta from m to new_m.
///
/// The new coordinate's initial values are derived from the residual
/// pattern — specifically, the per-entity mean residual magnitude, which
/// captures the relational signal the current m coordinates cannot express.
/// Not zero — zero would add nothing.
pub fn expand_m(delta: &Delta, new_m: usize) -> Delta {
    assert!(new_m > delta.m);
    let n = delta.dim;
    let old_m = delta.m;
    let mut expanded = Delta::zero(n, new_m);

    // Copy existing coordinates
    for i in 0..n {
        for j in 0..n {
            for l in 0..old_m {
                expanded.entries[i][j][l] = delta.entries[i][j][l].clone();
            }
        }
    }

    // New coordinate: seeded from residual magnitude per pair
    // For each (i,j) with i<j, the new coordinate = mean residual across triples
    // involving (i,j). This captures the relational signal the old m missed.
    let mut pair_residual = vec![vec![Q::zero(); n]; n];
    let mut pair_count = vec![vec![0u64; n]; n];
    for_each_residual(delta, |i, j, _k, _l, r| {
        let abs_r = if r < &Q::zero() { -r.clone() } else { r.clone() };
        pair_residual[i][j] = &pair_residual[i][j] + &abs_r;
        pair_count[i][j] += 1;
    });

    for i in 0..n {
        for j in (i+1)..n {
            if pair_count[i][j] > 0 {
                let mean = &pair_residual[i][j]
                    / &Q::new(BigInt::from(pair_count[i][j] as i64), BigInt::from(1));
                for l in old_m..new_m {
                    expanded.entries[i][j][l] = mean.clone();
                    expanded.entries[j][i][l] = -mean.clone(); // antisymmetry
                }
            }
        }
    }

    expanded
}

// ─── Dimensional Lifting for Memory Anchors ──────────────────────────

/// Lift an epsilon vector from n-dimensional operator space to new_n.
///
/// The old epsilon covers n(n-1)/2 directions. The lifted epsilon covers
/// new_n(new_n-1)/2 directions. Old directions are preserved in the
/// first n(n-1)/2 entries. New directions start at zero — the proven
/// path is valid in the subspace, new coordinates start unexplored.
///
/// Uses the same block-diagonal principle as operator lifting:
/// the old perturbation acts on the old dimensions, identity on the new.
pub fn lift_epsilon(old_eps: &[Q], old_n: usize, new_n: usize) -> Vec<Q> {
    let old_dirs = matrix::independent_dims(old_n);
    let new_dirs = matrix::independent_dims(new_n);
    let mut lifted = vec![Q::zero(); new_dirs.len()];

    // Map old directions to their positions in the new direction list
    for (old_idx, &(r, s)) in old_dirs.iter().enumerate() {
        // Same (r,s) pair appears at the same position in new_dirs
        // because independent_dims iterates r<s in the same order
        if let Some(new_idx) = new_dirs.iter().position(|&(nr, ns)| nr == r && ns == s) {
            lifted[new_idx] = old_eps[old_idx].clone();
        }
    }
    lifted
}

