/// Detect if the current state-space dimension n is insufficient.
///
/// When AᵀA from resolve() is rank-deficient (epsilon all zero)
/// but coherence is non-zero, the transformation requires more
/// state-space dimensions (more nodes in the relational field).
/// Returns Some(new_dim) if expansion is needed, None if current is sufficient.
pub fn detect_dimensional_need(delta: &Delta) -> Option<usize> {
    let resolution = resolve(delta);

    // If coherence is zero, no expansion needed
    if resolution.coherence_before.is_zero() { return None; }

    // If resolution didn't change anything (epsilon all zero), dim may be insufficient
    let eps_norm: Q = resolution.epsilon.iter()
        .map(|e| if e < &Q::zero() { -e.clone() } else { e.clone() })
        .sum();
    if eps_norm.is_zero() && resolution.coherence_before > Q::zero() {
        // Can't resolve at current dim — need more dimensions
        return Some(delta.dim + 1);
    }

    // Check if predicted coherence is still high relative to before
    // (resolution only marginally improves → dim may be limiting)
    if resolution.predicted_coherence_after > Q::zero() {
        let ratio = &resolution.predicted_coherence_after / &resolution.coherence_before;
        // If resolution only reduces coherence by <10%, dim might be limiting
        let threshold = Q::new(BigInt::from(9), BigInt::from(10));
        if ratio > threshold {
            return Some(delta.dim + 1);
        }
    }

    None
}

/// Expand a Delta to a higher dimension.
/// The new dimension entries are zero (the new relational axis starts empty).
/// The existing entries are preserved exactly.
pub fn expand_delta(delta: &Delta, new_dim: usize) -> Delta {
    assert!(new_dim > delta.dim);
    let mut expanded = Delta::zero(new_dim, delta.m);
    for i in 0..delta.dim {
        for j in 0..delta.dim {
            expanded.entries[i][j] = delta.entries[i][j].clone();
        }
    }
    expanded
}

// ─── Tests ─────────────────────────────────────────────────────────────

#[cfg(test)]
mod tests {
    use super::*;

    fn qr(n: i64, d: i64) -> Q { Q::new(BigInt::from(n), BigInt::from(d)) }

    fn incoherent_delta() -> Delta {
        // Δ_01=2, Δ_12=3, Δ_02=7. Cocycle requires Δ_02=2+3=5. Residual=2.
        let mut d = Delta::zero(3, 1);
        d.set_antisym(0, 1, vec![qr(2, 1)]);
        d.set_antisym(1, 2, vec![qr(3, 1)]);
        d.set_antisym(0, 2, vec![qr(7, 1)]);
        d
    }

    fn coherent_delta() -> Delta {
        let mut d = Delta::zero(3, 1);
        d.set_antisym(0, 1, vec![qr(1, 1)]);
        d.set_antisym(1, 2, vec![qr(1, 2)]);
        d.set_antisym(0, 2, vec![qr(3, 2)]);
        d
    }

    #[test]
    fn test_decompose_incoherent_has_residuals() {
        let d = incoherent_delta();
        let decomp = decompose(&d);
        assert!(!decomp.is_cocycle);
        assert!(decomp.coherence > Q::zero());
        assert!(!decomp.residuals.is_empty());
    }

    #[test]
    fn test_decompose_coherent_is_cocycle() {
        let d = coherent_delta();
        let decomp = decompose(&d);
        assert!(decomp.is_cocycle);
        assert_eq!(decomp.coherence, Q::zero());
        assert!(decomp.residuals.is_empty());
    }

    #[test]
    fn test_decompose_coherence_positive_for_incoherent() {
        let d = incoherent_delta();
        let decomp = decompose(&d);
        assert!(decomp.coherence > Q::zero(), "Incoherent delta must have positive decomposition coherence");
        // coherence_functional uses L1 (Σ|R|), decompose uses L2² (Σ R²)
        // Both are positive for incoherent deltas, both zero for cocycles.
        let c = coherence_functional(&d);
        assert!(c > Q::zero(), "L1 coherence must also be positive");
    }

    #[test]
    fn test_resolve_produces_epsilon() {
        let d = incoherent_delta();
        let res = resolve(&d);
        assert!(res.resolved);
        assert_eq!(res.epsilon.len(), 3); // 3 independent dims for 3×3
        assert!(res.coherence_before > Q::zero());
    }

    #[test]
    fn test_resolve_predicts_improvement() {
        let d = incoherent_delta();
        let res = resolve(&d);
        assert!(res.predicted_coherence_after < res.coherence_before,
            "Resolution should predict coherence improvement: before={}, predicted={}",
            res.coherence_before, res.predicted_coherence_after);
    }

    #[test]
    fn test_propose_reduces_coherence() {
        let d = incoherent_delta();
        let c_before = coherence_functional(&d);
        if let Some((op, _)) = propose(&d) {
            let result = op.apply(&d).unwrap();
            let projected = pi_g_project(&result);
            let c_after = coherence_functional(&projected);
            assert!(c_after < c_before,
                "Proposal should reduce coherence: before={}, after={}", c_before, c_after);
        } else {
            panic!("Must produce a proposal for incoherent state");
        }
    }

    #[test]
    fn test_propose_4x4() {
        let mut d = Delta::zero(4, 1);
        d.set_antisym(0, 1, vec![qr(1, 1)]);
        d.set_antisym(0, 2, vec![qr(3, 1)]);
        d.set_antisym(1, 2, vec![qr(7, 1)]); // not cocycle
        let c_before = coherence_functional(&d);
        assert!(c_before > Q::zero());
        if let Some((op, _)) = propose(&d) {
            let result = op.apply(&d).unwrap();
            let projected = pi_g_project(&result);
            let c_after = coherence_functional(&projected);
            assert!(c_after < c_before, "4×4 proposal should reduce coherence");
        }
    }

    #[test]
    fn test_propose_coherent_returns_none() {
        let d = coherent_delta();
        assert!(propose(&d).is_none(), "Coherent state should produce no proposal");
    }

    #[test]
    fn test_resolution_dimension_agnostic() {
        let mut d = Delta::zero(5, 1);
        d.set_antisym(0, 1, vec![qr(1, 1)]);
        d.set_antisym(0, 2, vec![qr(2, 1)]);
        d.set_antisym(1, 2, vec![qr(5, 1)]); // not cocycle
        let res = resolve(&d);
        assert_eq!(res.directions.len(), 10); // 5×4/2 = 10
        assert_eq!(res.epsilon.len(), 10);
        assert!(res.resolved);
    }

    #[test]
    fn test_iterated_resolution_converges_more() {
        let d = incoherent_delta();
        let c_before = coherence_functional(&d);

        // Single resolution
        let single_res = resolve(&d);
        let single_op = matrix::operator_from_epsilons(
            &single_res.epsilon, &single_res.directions, 3, 0,
        ).unwrap();
        let single_result = pi_g_project(&single_op.apply(&d).unwrap());
        let c_single = coherence_functional(&single_result);

        // Iterated resolution (5 iterations)
        let (iter_op, _) = propose(&d).unwrap();
        let iter_result = pi_g_project(&iter_op.apply(&d).unwrap());
        let c_iterated = coherence_functional(&iter_result);

        assert!(c_single < c_before, "Single resolution must improve");
        assert!(c_iterated <= c_single,
            "Iterated resolution must be at least as good as single: single={}, iterated={}",
            c_single, c_iterated);
    }

    #[test]
    fn test_single_resolution_4x4() {
        // 4×4 single resolution (iterated is expensive at higher dims)
        let mut d = Delta::zero(4, 1);
        d.set_antisym(0, 1, vec![qr(1, 1)]);
        d.set_antisym(0, 2, vec![qr(3, 1)]);
        d.set_antisym(1, 2, vec![qr(7, 1)]); // breaks cocycle
        let _c_before = coherence_functional(&d);
        let res = resolve(&d);
        assert!(res.predicted_coherence_after < res.coherence_before,
            "4×4 resolution must predict improvement");
    }

    #[test]
    fn test_perturbation_matrix_correct() {
        let d = incoherent_delta();
        let decomp = decompose(&d);
        // Verify perturbation is consistent with actual operator application
        let dirs = matrix::independent_dims(3);
        let eps = vec![qr(1, 100), Q::zero(), Q::zero()]; // small perturbation in direction 0
        let op = matrix::operator_from_epsilons(&eps, &dirs, 3, 0).unwrap();
        let perturbed = op.apply(&d).unwrap();
        let projected = pi_g_project(&perturbed);

        // The linear model predicts the residual change
        for res in &decomp.residuals {
            let predicted_change = residual_perturbation(&d, res.i, res.j, res.k, res.l, dirs[0].0, dirs[0].1)
                * &qr(1, 100);
            // This should be close to the actual change (up to O(ε²))
            let actual_new_residual = &projected.entries[res.i][res.k][res.l]
                - &projected.entries[res.i][res.j][res.l]
                - &projected.entries[res.j][res.k][res.l];
            let predicted_new = &res.value + &predicted_change;
            let diff = &actual_new_residual - &predicted_new;
            let abs_diff = if diff < Q::zero() { -diff } else { diff };
            // O(ε²) = O(1/10000) — should be small
            assert!(abs_diff < qr(1, 10),
                "Perturbation model must match actual to O(ε²)");
        }
    }

    // ─── Alignment score tests ────────────────────────────────────

    #[test]
    fn test_optimal_basis_from_incoherent() {
        let d = incoherent_delta();
        let basis = OptimalBasis::from_delta(&d, 0);
        assert!(basis.norm_squared > Q::zero(), "Basis must be non-zero for incoherent state");
        assert!(basis.coherence > Q::zero());
    }

    #[test]
    fn test_optimal_basis_from_coherent_is_zero() {
        let d = coherent_delta();
        let basis = OptimalBasis::from_delta(&d, 0);
        assert_eq!(basis.norm_squared, Q::zero(), "Coherent state has zero basis");
    }

    #[test]
    fn test_alignment_score_of_optimal_operator() {
        let d = incoherent_delta();
        let basis = OptimalBasis::from_delta(&d, 0);

        // Build an operator exactly aligned with ε*
        if let Some(op) = matrix::operator_from_epsilons(&basis.direction, &basis.dims, 3, 0) {
            let alpha = basis.alignment_score(&op);
            // Should be close to 1 (exact alignment) — may not be exactly 1
            // because operator_from_epsilons adds antisymmetric perturbation
            assert!(alpha > Q::zero(), "Optimal operator must have positive alignment");
        }
    }

    #[test]
    fn test_alignment_score_of_identity_is_zero() {
        let d = incoherent_delta();
        let basis = OptimalBasis::from_delta(&d, 0);
        let id_op = Operator {
            id: 0,
            matrix: matrix::identity(3),
            matrix_inv: matrix::identity(3),
            det_sign_positive: true,
        };
        let alpha = basis.alignment_score(&id_op);
        assert_eq!(alpha, Q::zero(), "Identity operator has zero alignment");
    }

    #[test]
    fn test_alignment_score_opposite_direction() {
        let d = incoherent_delta();
        let basis = OptimalBasis::from_delta(&d, 0);

        // Build operator in the OPPOSITE direction
        let neg_direction: Vec<Q> = basis.direction.iter().map(|e| -e.clone()).collect();
        if let Some(op) = matrix::operator_from_epsilons(&neg_direction, &basis.dims, 3, 0) {
            let alpha = basis.alignment_score(&op);
            assert!(alpha < Q::zero(), "Opposite direction must have negative alignment");
        }
    }

    #[test]
    fn test_basis_staleness() {
        let d = incoherent_delta();
        let basis = OptimalBasis::from_delta(&d, 100);
        assert!(!basis.is_stale(105, 10));
        assert!(basis.is_stale(115, 10));
    }

    // ─── D.COORD.GENESIS.1 tests ─────────────────────────────────

    #[test]
    fn test_genesis_alignment_at_genesis() {
        let d = coherent_delta();
        let genesis = coherent_delta(); // same as current = at genesis
        let basis = OptimalBasis::from_delta(&d, 0);
        let id_op = Operator {
            id: 0, matrix: matrix::identity(3), matrix_inv: matrix::identity(3),
            det_sign_positive: true,
        };
        let alpha_g = basis.genesis_alignment(&id_op, &d, &genesis);
        assert_eq!(alpha_g, Q::one(), "At genesis → α_genesis = 1");
    }

    #[test]
    fn test_genesis_alignment_away_from_genesis() {
        let current = incoherent_delta();
        let genesis = coherent_delta();
        let basis = OptimalBasis::from_delta(&current, 0);

        // Build an operator that moves AWAY from genesis
        let dirs = matrix::independent_dims(3);
        let mut away_eps = vec![Q::zero(); dirs.len()];
        // Direction away = current - genesis, so operator in THAT direction moves further away
        for (idx, &(r, s)) in dirs.iter().enumerate() {
            away_eps[idx] = &current.entries[r][s][0] - &genesis.entries[r][s][0];
        }
        if let Some(away_op) = matrix::operator_from_epsilons(&away_eps, &dirs, 3, 0) {
            let alpha_g = basis.genesis_alignment(&away_op, &current, &genesis);
            // Moving away from genesis should give negative α_genesis
            // (inner product of away-direction with toward-genesis is negative)
            assert!(alpha_g < Q::zero() || alpha_g.is_zero(),
                "Moving away from genesis → α_genesis ≤ 0, got {}", alpha_g);
        }
    }

    // ─── D.MESH.DIM.1 tests ──────────────────────────────────────

    #[test]
    fn test_no_dimensional_need_when_coherent() {
        let d = coherent_delta();
        assert_eq!(detect_dimensional_need(&d), None);
    }

    #[test]
    fn test_expand_delta_preserves_entries() {
        let d = incoherent_delta();
        let expanded = expand_delta(&d, 5);
        assert_eq!(expanded.dim, 5);
        assert_eq!(expanded.m, d.m);
        // Original entries preserved
        for i in 0..3 {
            for j in 0..3 {
                assert_eq!(expanded.entries[i][j], d.entries[i][j]);
            }
        }
        // New entries are zero
        for j in 0..5 {
            assert_eq!(expanded.entries[3][j][0], Q::zero());
            assert_eq!(expanded.entries[4][j][0], Q::zero());
        }
    }

    // ─── T.TRANSMUTE.1 — m-Expansion Tests ──────────────────────────

    #[test]
    fn test_coherent_delta_no_m_expansion() {
        let d = coherent_delta();
        assert!(detect_m_expansion_need(&d).is_none(),
            "coherent state must not trigger m-expansion");
    }

    #[test]
    fn test_expand_m_preserves_existing_coords() {
        let mut d = Delta::zero(3, 1);
        d.set_antisym(0, 1, vec![qr(1, 1)]);
        d.set_antisym(1, 2, vec![qr(1, 2)]);
        d.set_antisym(0, 2, vec![qr(3, 2)]);

        let expanded = expand_m(&d, 3);
        assert_eq!(expanded.dim, 3);
        assert_eq!(expanded.m, 3);

        // First coordinate preserved exactly
        for i in 0..3 {
            for j in 0..3 {
                assert_eq!(expanded.entries[i][j][0], d.entries[i][j][0],
                    "existing coord must be preserved at ({},{})", i, j);
            }
        }
    }

    #[test]
    fn test_expand_m_new_coords_from_residual() {
        // Build an incoherent delta so residuals exist
        let mut d = Delta::zero(3, 1);
        d.set_antisym(0, 1, vec![qr(1, 1)]);
        d.set_antisym(1, 2, vec![qr(1, 2)]);
        d.set_antisym(0, 2, vec![qr(1, 3)]); // NOT 3/2 → incoherent

        let expanded = expand_m(&d, 2);
        assert_eq!(expanded.m, 2);

        // New coordinate should be non-zero (seeded from residual)
        let mut has_nonzero = false;
        for i in 0..3 {
            for j in 0..3 {
                if !expanded.entries[i][j][1].is_zero() {
                    has_nonzero = true;
                }
            }
        }
        assert!(has_nonzero, "new coordinate must be seeded from residual, not zero");

        // Antisymmetry preserved in new coordinate
        for i in 0..3 {
            for j in 0..3 {
                let sum = &expanded.entries[i][j][1] + &expanded.entries[j][i][1];
                assert!(sum.is_zero(),
                    "antisymmetry must hold in new coord at ({},{})", i, j);
            }
        }
    }

    #[test]
    fn test_expand_m_coherent_gives_zero_new_coords() {
        // Coherent delta: no residuals → new coord should be zero
        let d = coherent_delta();
        let expanded = expand_m(&d, 2);

        for i in 0..3 {
            for j in 0..3 {
                assert!(expanded.entries[i][j][1].is_zero(),
                    "coherent delta should produce zero new coord at ({},{})", i, j);
            }
        }
    }
}
